/**
 * Restore key import/export helpers.
 */
import { defaultEdgeCaseScanConfig, sanitizeEdgeCaseScanConfig, } from '@/services/anonymization/edgeCaseConfig';
const isRecord = (value) => typeof value === 'object' && value !== null && !Array.isArray(value);
const validateRestoreKeyShape = (value) => {
    if (!isRecord(value)) {
        return false;
    }
    const hasRequiredStrings = typeof value.version === 'string' &&
        typeof value.workbookGuid === 'string' &&
        typeof value.createdAt === 'string';
    const hasMatchingMode = value.matchingMode === 'exact' ||
        value.matchingMode === 'starts-with' ||
        value.matchingMode === 'includes';
    const hasNormalization = isRecord(value.normalization) &&
        typeof value.normalization.caseInsensitive === 'boolean' &&
        typeof value.normalization.ignorePunctuation === 'boolean' &&
        typeof value.normalization.ignoreWhitespace === 'boolean';
    const hasTaggedRanges = Array.isArray(value.taggedRanges);
    const hasNameMap = Array.isArray(value.nameMap);
    return hasRequiredStrings && hasMatchingMode && hasNormalization && hasTaggedRanges && hasNameMap;
};
export const buildRestoreKeyFilename = (keyData) => {
    const dateStamp = new Date().toISOString().replace(/[:.]/g, '-');
    return `reclude-key-${keyData.workbookGuid}-${dateStamp}.json`;
};
export const downloadRestoreKey = (keyData) => {
    const filename = buildRestoreKeyFilename(keyData);
    const blob = new Blob([JSON.stringify(keyData, null, 2)], { type: 'application/json' });
    const objectUrl = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = objectUrl;
    link.download = filename;
    link.click();
    URL.revokeObjectURL(objectUrl);
    return filename;
};
export const parseRestoreKeyFile = async (file) => {
    const fileText = await file.text();
    let parsed;
    try {
        parsed = JSON.parse(fileText);
    }
    catch (error) {
        throw new Error('Restore key is not valid JSON.');
    }
    if (!validateRestoreKeyShape(parsed)) {
        throw new Error('Restore key JSON does not match expected schema.');
    }
    return {
        ...parsed,
        edgeCaseScanConfig: sanitizeEdgeCaseScanConfig(parsed.edgeCaseScanConfig, defaultEdgeCaseScanConfig()),
    };
};
