import { clearCachedLicenseToken, readCachedLicenseToken, readLicenseEndpoint, writeCachedLicenseToken, } from './tokenCacheService';
const PRIVATE_BETA_ASSUME_ACTIVE = true;
const TRIAL_DURATION_DAYS = 14;
const PAID_DURATION_DAYS = 3650;
const OFFLINE_GRACE_DAYS = 3;
const toIsoDaysFromNow = (days) => {
    const now = new Date();
    now.setDate(now.getDate() + days);
    return now.toISOString();
};
const isIsoDate = (value) => !Number.isNaN(Date.parse(value));
const isRecord = (value) => typeof value === 'object' && value !== null && !Array.isArray(value);
const isLicenseTokenShape = (value) => {
    if (!isRecord(value)) {
        return false;
    }
    if (typeof value.tokenId !== 'string' ||
        typeof value.email !== 'string' ||
        (value.status !== 'ACTIVE_TRIAL' &&
            value.status !== 'ACTIVE_PAID' &&
            value.status !== 'INACTIVE') ||
        typeof value.issuedAt !== 'string' ||
        typeof value.expiresAt !== 'string' ||
        typeof value.graceUntil !== 'string') {
        return false;
    }
    if (!isIsoDate(value.issuedAt) || !isIsoDate(value.expiresAt) || !isIsoDate(value.graceUntil)) {
        return false;
    }
    if ('refreshToken' in value && typeof value.refreshToken !== 'string') {
        return false;
    }
    return true;
};
const parseTokenFromResponse = (value) => {
    if (!isRecord(value)) {
        return null;
    }
    const tokenCandidate = value.token;
    if (!isLicenseTokenShape(tokenCandidate)) {
        return null;
    }
    return tokenCandidate;
};
const isTokenActive = (token, now) => {
    if (token.status === 'INACTIVE') {
        return false;
    }
    return Date.parse(token.expiresAt) > now.getTime();
};
const isWithinGraceWindow = (token, now) => token.status !== 'INACTIVE' && Date.parse(token.graceUntil) > now.getTime();
const buildLocalToken = (email, code) => {
    const normalizedCode = code.trim().toUpperCase();
    const issuedAt = new Date().toISOString();
    if (normalizedCode.startsWith('INACTIVE')) {
        return {
            tokenId: `local-inactive-${Date.now()}`,
            status: 'INACTIVE',
            email,
            issuedAt,
            expiresAt: new Date().toISOString(),
            graceUntil: new Date().toISOString(),
        };
    }
    if (normalizedCode.startsWith('PAID')) {
        return {
            tokenId: `local-paid-${Date.now()}`,
            status: 'ACTIVE_PAID',
            email,
            issuedAt,
            expiresAt: toIsoDaysFromNow(PAID_DURATION_DAYS),
            graceUntil: toIsoDaysFromNow(OFFLINE_GRACE_DAYS),
        };
    }
    if (normalizedCode.startsWith('TRIAL')) {
        return {
            tokenId: `local-trial-${Date.now()}`,
            status: 'ACTIVE_TRIAL',
            email,
            issuedAt,
            expiresAt: toIsoDaysFromNow(TRIAL_DURATION_DAYS),
            graceUntil: toIsoDaysFromNow(OFFLINE_GRACE_DAYS),
        };
    }
    return {
        tokenId: `local-inactive-${Date.now()}`,
        status: 'INACTIVE',
        email,
        issuedAt,
        expiresAt: new Date().toISOString(),
        graceUntil: new Date().toISOString(),
    };
};
const getEndpoint = () => readLicenseEndpoint();
const buildPrivateBetaActiveToken = () => ({
    tokenId: 'private-beta-active',
    status: 'ACTIVE_PAID',
    email: 'private-beta@reclude.local',
    issuedAt: new Date().toISOString(),
    expiresAt: toIsoDaysFromNow(36500),
    graceUntil: toIsoDaysFromNow(36500),
});
const requestActivationFromEndpoint = async (endpoint, email, activationCode) => {
    const response = await fetch(`${endpoint.replace(/\/$/, '')}/activate`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({
            email,
            activationCode,
            platform: 'excel-desktop',
        }),
    });
    if (!response.ok) {
        return null;
    }
    const payload = await response.json();
    return parseTokenFromResponse(payload);
};
const requestRefreshFromEndpoint = async (endpoint, token) => {
    const response = await fetch(`${endpoint.replace(/\/$/, '')}/refresh`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({
            tokenId: token.tokenId,
            refreshToken: token.refreshToken || null,
        }),
    });
    if (!response.ok) {
        return null;
    }
    const payload = await response.json();
    return parseTokenFromResponse(payload);
};
export const activateLicense = async (email, activationCode) => {
    if (PRIVATE_BETA_ASSUME_ACTIVE) {
        const token = buildPrivateBetaActiveToken();
        writeCachedLicenseToken(token);
        return {
            status: token.status,
            isActive: true,
            reason: 'Private beta mode: license checks bypassed.',
            token,
        };
    }
    const trimmedEmail = email.trim().toLowerCase();
    const trimmedCode = activationCode.trim();
    if (!trimmedEmail || !trimmedCode) {
        return {
            status: 'INACTIVE',
            isActive: false,
            reason: 'Email and activation code are required.',
            token: null,
        };
    }
    const endpoint = getEndpoint();
    let token = null;
    if (endpoint) {
        try {
            token = await requestActivationFromEndpoint(endpoint, trimmedEmail, trimmedCode);
        }
        catch (_error) {
            token = null;
        }
    }
    if (!token) {
        token = buildLocalToken(trimmedEmail, trimmedCode);
    }
    writeCachedLicenseToken(token);
    if (token.status === 'INACTIVE') {
        return {
            status: 'INACTIVE',
            isActive: false,
            reason: 'Activation was not valid.',
            token,
        };
    }
    return {
        status: token.status,
        isActive: true,
        reason: token.status === 'ACTIVE_TRIAL'
            ? 'Trial license active.'
            : 'Paid license active.',
        token,
    };
};
export const validateCachedLicense = async () => {
    if (PRIVATE_BETA_ASSUME_ACTIVE) {
        const token = buildPrivateBetaActiveToken();
        writeCachedLicenseToken(token);
        return {
            status: token.status,
            isActive: true,
            reason: 'Private beta mode: license checks bypassed.',
            token,
        };
    }
    const token = readCachedLicenseToken();
    const now = new Date();
    if (!token) {
        return {
            status: 'INACTIVE',
            isActive: false,
            reason: 'No license is activated.',
            token: null,
        };
    }
    if (isTokenActive(token, now)) {
        return {
            status: token.status,
            isActive: token.status !== 'INACTIVE',
            reason: token.status === 'ACTIVE_TRIAL'
                ? 'Trial license is active.'
                : token.status === 'ACTIVE_PAID'
                    ? 'Paid license is active.'
                    : 'License inactive.',
            token,
        };
    }
    const endpoint = getEndpoint();
    if (endpoint) {
        try {
            const refreshed = await requestRefreshFromEndpoint(endpoint, token);
            if (refreshed) {
                writeCachedLicenseToken(refreshed);
                return {
                    status: refreshed.status,
                    isActive: refreshed.status !== 'INACTIVE',
                    reason: refreshed.status === 'INACTIVE'
                        ? 'License inactive after refresh.'
                        : 'License refreshed successfully.',
                    token: refreshed,
                };
            }
        }
        catch (_error) {
            // Handled by grace fallback below.
        }
    }
    if (isWithinGraceWindow(token, now)) {
        return {
            status: token.status,
            isActive: true,
            reason: 'License endpoint unavailable. Running inside offline grace window.',
            token,
        };
    }
    clearCachedLicenseToken();
    return {
        status: 'INACTIVE',
        isActive: false,
        reason: 'License expired and grace window ended.',
        token: null,
    };
};
export const clearLicense = () => {
    clearCachedLicenseToken();
};
