let pendingIntent = null;
const listeners = new Set();
export const queueCommandIntent = (intent) => {
    pendingIntent = intent;
    listeners.forEach((listener) => listener(intent));
};
export const consumeQueuedCommandIntent = () => {
    const currentIntent = pendingIntent;
    pendingIntent = null;
    return currentIntent;
};
export const subscribeToCommandIntents = (listener) => {
    listeners.add(listener);
    return () => {
        listeners.delete(listener);
    };
};
