const normalizeSegments = (input) => {
    return input
        .trim()
        .split('.')
        .map((segment) => Number.parseInt(segment, 10))
        .filter((segment) => Number.isFinite(segment));
};
export const compareVersions = (left, right) => {
    const leftSegments = normalizeSegments(left);
    const rightSegments = normalizeSegments(right);
    const length = Math.max(leftSegments.length, rightSegments.length);
    for (let index = 0; index < length; index += 1) {
        const leftValue = leftSegments[index] ?? 0;
        const rightValue = rightSegments[index] ?? 0;
        if (leftValue > rightValue) {
            return 1;
        }
        if (leftValue < rightValue) {
            return -1;
        }
    }
    return 0;
};
export const isVersionLessThan = (left, right) => compareVersions(left, right) < 0;
export const isVersionGreaterThan = (left, right) => compareVersions(left, right) > 0;
