/**
 * Text normalization and matching helpers for anonymization and restore.
 */
const normalizedCharacterPattern = /[\p{L}\p{N}]/u;
const buildNormalizedIndexMap = (value) => {
    const normalizedChars = [];
    const indexMap = [];
    for (let index = 0; index < value.length; index += 1) {
        const character = value.charAt(index);
        if (!character) {
            continue;
        }
        if (normalizedCharacterPattern.test(character)) {
            normalizedChars.push(character.toLowerCase());
            indexMap.push(index);
        }
    }
    return {
        normalized: normalizedChars.join(''),
        indexMap,
    };
};
const findAllNormalizedMatches = (haystack, needle) => {
    if (!needle) {
        return [];
    }
    const matches = [];
    let currentIndex = 0;
    while (currentIndex <= haystack.length - needle.length) {
        const matchIndex = haystack.indexOf(needle, currentIndex);
        if (matchIndex === -1) {
            break;
        }
        matches.push(matchIndex);
        currentIndex = matchIndex + needle.length;
    }
    return matches;
};
const mergeRanges = (ranges) => {
    if (ranges.length < 2) {
        return ranges;
    }
    const sorted = [...ranges].sort((left, right) => left.start - right.start);
    const first = sorted[0];
    if (!first) {
        return [];
    }
    const merged = [first];
    for (let index = 1; index < sorted.length; index += 1) {
        const current = sorted[index];
        const previous = merged[merged.length - 1];
        if (!current || !previous) {
            continue;
        }
        if (current.start <= previous.end + 1) {
            previous.end = Math.max(previous.end, current.end);
        }
        else {
            merged.push(current);
        }
    }
    return merged;
};
const replaceRanges = (input, ranges, replacement) => {
    if (ranges.length === 0) {
        return input;
    }
    let output = input;
    const ordered = [...ranges].sort((left, right) => right.start - left.start);
    for (const range of ordered) {
        output = `${output.slice(0, range.start)}${replacement}${output.slice(range.end + 1)}`;
    }
    return output;
};
export const normalizeText = (value) => buildNormalizedIndexMap(value).normalized;
export const replaceTextByMode = ({ input, normalizedNeedle, replacement, mode, }) => {
    if (!input || !normalizedNeedle) {
        return { output: input, replacements: 0 };
    }
    const { normalized, indexMap } = buildNormalizedIndexMap(input);
    if (!normalized) {
        return { output: input, replacements: 0 };
    }
    if (mode === 'exact') {
        if (normalized === normalizedNeedle) {
            return { output: replacement, replacements: 1 };
        }
        return { output: input, replacements: 0 };
    }
    const matchIndexes = mode === 'starts-with'
        ? normalized.startsWith(normalizedNeedle)
            ? [0]
            : []
        : findAllNormalizedMatches(normalized, normalizedNeedle);
    if (matchIndexes.length === 0) {
        return { output: input, replacements: 0 };
    }
    const ranges = [];
    for (const matchIndex of matchIndexes) {
        const normalizedEnd = matchIndex + normalizedNeedle.length - 1;
        const start = indexMap[matchIndex];
        const end = indexMap[normalizedEnd];
        if (start === undefined || end === undefined) {
            continue;
        }
        ranges.push({ start, end });
    }
    if (ranges.length === 0) {
        return { output: input, replacements: 0 };
    }
    const merged = mergeRanges(ranges);
    const output = replaceRanges(input, merged, replacement);
    return {
        output,
        replacements: merged.length,
    };
};
