/**
 * Workbook identity persistence used to validate restore keys.
 */
const WORKBOOK_GUID_SETTING_KEY = 'recludeWorkbookGuid';
const LEGACY_WORKBOOK_GUID_SETTING_KEY = 'xlsMaskerWorkbookGuid';
const createGuid = () => {
    if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
        return crypto.randomUUID();
    }
    return `xxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx`.replace(/[xy]/g, (character) => {
        const random = Math.floor(Math.random() * 16);
        const value = character === 'x' ? random : (random & 0x3) | 0x8;
        return value.toString(16);
    });
};
const saveDocumentSettings = async () => new Promise((resolve, reject) => {
    Office.context.document.settings.saveAsync((result) => {
        if (result.status === Office.AsyncResultStatus.Succeeded) {
            resolve();
        }
        else {
            reject(new Error(result.error?.message || 'Failed to save workbook settings.'));
        }
    });
});
export const getOrCreateWorkbookGuid = async () => {
    const existingGuid = Office.context.document.settings.get(WORKBOOK_GUID_SETTING_KEY) ||
        Office.context.document.settings.get(LEGACY_WORKBOOK_GUID_SETTING_KEY);
    if (typeof existingGuid === 'string' && existingGuid.trim()) {
        // Ensure future reads use the Reclude key while preserving backward compatibility.
        Office.context.document.settings.set(WORKBOOK_GUID_SETTING_KEY, existingGuid);
        return existingGuid;
    }
    const generatedGuid = createGuid();
    Office.context.document.settings.set(WORKBOOK_GUID_SETTING_KEY, generatedGuid);
    await saveDocumentSettings();
    return generatedGuid;
};
