import { compareVersions, isVersionLessThan } from '@/services/updates/semverService';
const UPDATE_CACHE_KEY = 'reclude.update.lastResult';
const UPDATE_CACHE_TTL_MS = 24 * 60 * 60 * 1000;
const isValidFeedData = (value) => {
    if (!value || typeof value !== 'object') {
        return false;
    }
    const candidate = value;
    return (typeof candidate.channel === 'string' &&
        typeof candidate.latestWebVersion === 'string' &&
        typeof candidate.latestManifestVersion === 'string' &&
        typeof candidate.latestInstallerVersion === 'string' &&
        typeof candidate.minimumSupportedManifestVersion === 'string' &&
        typeof candidate.minimumSupportedInstallerVersion === 'string' &&
        typeof candidate.publishedAt === 'string' &&
        typeof candidate.downloads === 'object');
};
const buildDownloadUrl = (feed, platform) => {
    if (platform === 'mac') {
        return feed.downloads.mac?.url || null;
    }
    if (platform === 'windows') {
        return feed.downloads.windows?.url || null;
    }
    return feed.downloads.mac?.url || feed.downloads.windows?.url || null;
};
const buildDisabledResult = (installed) => ({
    availability: 'disabled',
    checkedAt: new Date().toISOString(),
    installed,
    feed: null,
    downloadUrl: null,
    message: 'Update checks are disabled in local development builds.',
});
const buildUpToDateResult = (installed, feed, platform) => ({
    availability: 'up-to-date',
    checkedAt: new Date().toISOString(),
    installed,
    feed,
    downloadUrl: buildDownloadUrl(feed, platform),
    message: 'Reclude is up to date.',
});
const buildRecommendedResult = (installed, feed, platform) => ({
    availability: 'recommended',
    checkedAt: new Date().toISOString(),
    installed,
    feed,
    downloadUrl: buildDownloadUrl(feed, platform),
    message: feed.message?.trim() || 'A newer Reclude installer is available.',
});
const buildRequiredResult = (installed, feed, platform) => ({
    availability: 'required',
    checkedAt: new Date().toISOString(),
    installed,
    feed,
    downloadUrl: buildDownloadUrl(feed, platform),
    message: feed.message?.trim() ||
        'This Reclude installation is no longer supported and must be updated.',
});
const buildErrorResult = (installed, error) => ({
    availability: 'error',
    checkedAt: new Date().toISOString(),
    installed,
    feed: null,
    downloadUrl: null,
    message: 'Unable to check for updates.',
    error,
});
export const loadCachedUpdateCheck = () => {
    try {
        const raw = window.localStorage.getItem(UPDATE_CACHE_KEY);
        if (!raw) {
            return null;
        }
        return JSON.parse(raw);
    }
    catch (_error) {
        return null;
    }
};
export const saveCachedUpdateCheck = (result) => {
    const payload = {
        checkedAt: result.checkedAt,
        result,
    };
    window.localStorage.setItem(UPDATE_CACHE_KEY, JSON.stringify(payload));
};
export const isCachedUpdateCheckFresh = (cached) => {
    if (!cached) {
        return false;
    }
    const checkedAtMs = Date.parse(cached.checkedAt);
    if (Number.isNaN(checkedAtMs)) {
        return false;
    }
    return Date.now() - checkedAtMs < UPDATE_CACHE_TTL_MS;
};
const evaluateFeed = (installed, feed, platform) => {
    const manifestTooOld = isVersionLessThan(installed.manifestVersion, feed.minimumSupportedManifestVersion);
    const installerTooOld = isVersionLessThan(installed.installerVersion, feed.minimumSupportedInstallerVersion);
    if (manifestTooOld || installerTooOld || feed.requiredUpdate) {
        return buildRequiredResult(installed, feed, platform);
    }
    const installerBehind = compareVersions(installed.installerVersion, feed.latestInstallerVersion) < 0;
    const manifestBehind = compareVersions(installed.manifestVersion, feed.latestManifestVersion) < 0;
    if (installerBehind || manifestBehind || feed.recommendedUpdate) {
        return buildRecommendedResult(installed, feed, platform);
    }
    return buildUpToDateResult(installed, feed, platform);
};
export const checkForUpdates = async (installed, platform, force = false) => {
    if (installed.isDevelopmentBuild || !installed.feedUrl) {
        const disabledResult = buildDisabledResult(installed);
        saveCachedUpdateCheck(disabledResult);
        return disabledResult;
    }
    if (!force) {
        const cached = loadCachedUpdateCheck();
        if (cached && isCachedUpdateCheckFresh(cached)) {
            return cached.result;
        }
    }
    try {
        const response = await fetch(installed.feedUrl, { cache: 'no-store' });
        if (!response.ok) {
            throw new Error(`Update feed request failed with status ${response.status}.`);
        }
        const payload = (await response.json());
        if (!isValidFeedData(payload)) {
            throw new Error('Update feed payload is invalid.');
        }
        const result = evaluateFeed(installed, payload, platform);
        saveCachedUpdateCheck(result);
        return result;
    }
    catch (error) {
        const result = buildErrorResult(installed, error instanceof Error ? error.message : 'Unknown update check error.');
        saveCachedUpdateCheck(result);
        return result;
    }
};
