/**
 * UI State Slice
 *
 * This slice manages the user interface state including modal visibility,
 * loading states, and error handling.
 */
import { createSlice } from '@reduxjs/toolkit';
const initialState = {
    isTaskPaneVisible: false,
    modal: {
        isOpen: false,
    },
    loading: {
        isLoading: false,
    },
    toasts: [],
    currentView: 'welcome',
    isOfficeInitialized: false,
};
export const uiSlice = createSlice({
    name: 'ui',
    initialState,
    reducers: {
        setTaskPaneVisible: (state, action) => {
            state.isTaskPaneVisible = action.payload;
        },
        setModal: (state, action) => {
            state.modal = { ...state.modal, ...action.payload };
        },
        closeModal: (state) => {
            state.modal.isOpen = false;
        },
        setLoading: (state, action) => {
            state.loading = { ...state.loading, ...action.payload };
        },
        addToast: (state, action) => {
            const toast = {
                ...action.payload,
                id: Date.now().toString(),
                timestamp: new Date(),
            };
            state.toasts.push(toast);
        },
        removeToast: (state, action) => {
            state.toasts = state.toasts.filter(toast => toast.id !== action.payload);
        },
        setCurrentView: (state, action) => {
            state.currentView = action.payload;
        },
        setOfficeInitialized: (state, action) => {
            state.isOfficeInitialized = action.payload;
        },
    },
});
export const { setTaskPaneVisible, setModal, closeModal, setLoading, addToast, removeToast, setCurrentView, setOfficeInitialized, } = uiSlice.actions;
export default uiSlice.reducer;
