/**
 * Deterministic pseudonym generation from tagged entity values.
 */
import { normalizeText } from './matchingService';
const sanitizePrefix = (designation) => {
    const alphanumericOnly = designation.replace(/[^a-zA-Z0-9]/g, '');
    return alphanumericOnly || 'Entity';
};
export const getDesignationLabel = (taggedRange) => taggedRange.designation === 'Custom'
    ? taggedRange.customDesignation?.trim() || 'Custom'
    : taggedRange.designation;
const buildMappingKey = (designation, sourceNormalized) => `${designation}::${sourceNormalized}`;
const buildSourceAnyKey = (sourceNormalized) => sourceNormalized;
const parsePseudonymIndex = (mapping) => {
    const prefix = sanitizePrefix(mapping.designation);
    const match = mapping.pseudonym.match(new RegExp(`^${prefix}-(\\d+)$`));
    if (!match) {
        return null;
    }
    const parsed = Number(match[1]);
    return Number.isFinite(parsed) ? parsed : null;
};
const normalizeExistingMappings = (existingMappings) => existingMappings.map((mapping) => ({
    ...mapping,
    source: mapping.source.trim(),
    sourceNormalized: mapping.sourceNormalized || normalizeText(mapping.source),
}));
export const buildNameMappings = (taggedValues, existingMappings = []) => {
    const normalizedExistingMappings = normalizeExistingMappings(existingMappings);
    const existingByKey = new Map();
    const existingBySourceAny = new Map();
    const existingByPseudonym = new Map();
    normalizedExistingMappings.forEach((mapping) => {
        existingByKey.set(buildMappingKey(mapping.designation, mapping.sourceNormalized), mapping);
        if (!existingBySourceAny.has(buildSourceAnyKey(mapping.sourceNormalized))) {
            existingBySourceAny.set(buildSourceAnyKey(mapping.sourceNormalized), mapping);
        }
        const pseudonymNormalized = normalizeText(mapping.pseudonym);
        if (pseudonymNormalized && !existingByPseudonym.has(pseudonymNormalized)) {
            existingByPseudonym.set(pseudonymNormalized, mapping);
        }
    });
    const dedupedSeeds = new Map();
    for (const taggedValue of taggedValues) {
        const currentValue = taggedValue.value.trim();
        if (!currentValue) {
            continue;
        }
        const currentNormalized = normalizeText(currentValue);
        if (!currentNormalized) {
            continue;
        }
        const taggedDesignation = getDesignationLabel(taggedValue.taggedRange);
        const existingMapping = existingByPseudonym.get(currentNormalized) ||
            existingByKey.get(buildMappingKey(taggedDesignation, currentNormalized)) ||
            existingBySourceAny.get(buildSourceAnyKey(currentNormalized));
        const source = existingMapping ? existingMapping.source : currentValue;
        if (!source) {
            continue;
        }
        const sourceNormalized = existingMapping?.sourceNormalized || normalizeText(source);
        if (!sourceNormalized) {
            continue;
        }
        const designation = existingMapping?.designation || taggedDesignation;
        const key = buildMappingKey(designation, sourceNormalized);
        if (!existingByKey.has(key) && !dedupedSeeds.has(key)) {
            dedupedSeeds.set(key, {
                designation,
                source,
                sourceNormalized,
            });
        }
    }
    const byDesignation = new Map();
    for (const seed of dedupedSeeds.values()) {
        const current = byDesignation.get(seed.designation) ?? [];
        current.push(seed);
        byDesignation.set(seed.designation, current);
    }
    const mappings = [...normalizedExistingMappings];
    const sortedDesignations = [...new Set([...normalizedExistingMappings.map((mapping) => mapping.designation), ...byDesignation.keys()])].sort((left, right) => left.localeCompare(right));
    for (const designation of sortedDesignations) {
        const existingEntries = normalizedExistingMappings
            .filter((mapping) => mapping.designation === designation)
            .sort((left, right) => {
            const leftIndex = parsePseudonymIndex(left);
            const rightIndex = parsePseudonymIndex(right);
            if (leftIndex !== null && rightIndex !== null && leftIndex !== rightIndex) {
                return leftIndex - rightIndex;
            }
            return left.sourceNormalized.localeCompare(right.sourceNormalized);
        });
        const entries = byDesignation.get(designation) ?? [];
        entries.sort((left, right) => left.sourceNormalized.localeCompare(right.sourceNormalized));
        const nextIndexSeed = existingEntries.reduce((maxIndex, entry) => {
            const parsedIndex = parsePseudonymIndex(entry);
            if (parsedIndex !== null) {
                return Math.max(maxIndex, parsedIndex);
            }
            return Math.max(maxIndex, existingEntries.length);
        }, 0);
        let nextIndex = nextIndexSeed + 1;
        const prefix = sanitizePrefix(designation);
        entries.forEach((entry) => {
            const pseudonym = `${prefix}-${String(nextIndex).padStart(3, '0')}`;
            nextIndex += 1;
            mappings.push({
                designation,
                source: entry.source,
                sourceNormalized: entry.sourceNormalized,
                pseudonym,
            });
        });
    }
    return mappings;
};
