const normalizeChannel = (value) => {
    if (value === 'stable' || value === 'preview' || value === 'development') {
        return value;
    }
    return 'unknown';
};
const resolveFeedUrl = (url, isDevelopmentBuild) => {
    if (isDevelopmentBuild) {
        return null;
    }
    return new URL('update-feed.json', url).toString();
};
export const getInstalledVersionInfo = () => {
    const currentUrl = new URL(window.location.href);
    const isDevelopmentBuild = currentUrl.hostname === 'localhost';
    const channel = normalizeChannel(currentUrl.searchParams.get('channel'));
    const manifestVersion = currentUrl.searchParams.get('manifestVersion')?.trim() || __APP_VERSION__;
    const installerVersion = currentUrl.searchParams.get('installerVersion')?.trim() || manifestVersion;
    return {
        appVersion: __APP_VERSION__,
        manifestVersion,
        installerVersion,
        channel: isDevelopmentBuild ? 'development' : channel,
        isDevelopmentBuild,
        feedUrl: resolveFeedUrl(currentUrl, isDevelopmentBuild),
    };
};
